const gemini = $input.first().json;
const sisteme_giris = new Date().toLocaleString('tr-TR');

let sonuc = {};
try {
  let metin = gemini.candidates[0].content.parts[0].text;
  const jsonMatch = metin.match(/\{[\s\S]*\}/);
  if (jsonMatch) sonuc = JSON.parse(jsonMatch[0]);
} catch (e) {
  sonuc = {};
}

return [{
  json: {
    Sisteme_Giris: sisteme_giris,
    Hasta_Adi: sonuc.hasta_adi || 'Okunamadı',
    Telefon: sonuc.telefon || '',
    Ulke: sonuc.ulke || '',
    Anket_Tarihi: sonuc.anket_tarihi || '',
    Hekim_Adi: sonuc.hekim_adi || '',
    Hekim_Puani: sonuc.hekim_puani || 0,
    Soru_1: sonuc.soru1 || 0,
    Soru_2: sonuc.soru2 || 0,
    Soru_3: sonuc.soru3 || 0,
    Soru_4: sonuc.soru4 || 0,
    Soru_5: sonuc.soru5 || 0,
    Soru_6: sonuc.soru6 || 0,
    Soru_7: sonuc.soru7 || 0
  }
}];
